{
  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using the terms from the earlier lesson content about cybersecurity concepts. Refer to the flashcards for clues.",
        "codeTemplate": "A ___ is a potential cause of an unwanted incident in cybersecurity, while a ___ is a weakness in a system that can be exploited.",
        "options": [
          "threat",
          "vulnerability",
          "data breach",
          "firewall"
        ],
        "correctAnswer": "threat,vulnerability",
        "explanation": "A threat is a potential cause of an unwanted incident, and a vulnerability is a weakness that can be exploited."
      },
      {
        "instruction": "Using your understanding of cybersecurity, fill in the blanks based on the earlier concepts discussed in this module.",
        "codeTemplate": "The practice of protecting systems, networks, and programs from ___ is known as ___.",
        "options": [
          "threats",
          "data analysis",
          "vulnerabilities",
          "cybersecurity"
        ],
        "correctAnswer": "threats,cybersecurity",
        "explanation": "Cybersecurity is the practice of protecting systems from threats."
      }
    ]
  }
}
